name:
fun TextInput(state: TextInputState, hint: String? = null, inputType: InputType = InputType.COMMON, readOnly: Boolean = false, maxLength: Int = 0, maxLines: Int = 1, minLines: Int = maxLines, clearButton: Boolean = true, leadingIcon: () -> Unit? = null, trailingIcon: () -> Unit? = if (clearButton) {
        {
            ClickIcon(
                icon = M3Icons.Clear,
                onClick = {
                    state.text = ""
                    state.overflow = false
                }
            )
        }
    } else null, imeAction: ImeAction = ImeAction.Done, onImeClick: KeyboardActionScope.() -> Unit? = null, modifier: Modifier = Modifier)

